import ast

def evaluate_expression(expr):
    # Define allowed functions and operators
    allowed_ops = {'+', '-', '*', '/', '**', '%', '(', ')', 'sin', 'cos', 'tan', 'log', 'sqrt', 'abs', 'min', 'max', 'round'}
    allowed_modules = ['math']

    # Check if the expression is valid and safe
    try:
        # Parse the expression using AST
        tree = ast.parse(expr, mode='eval')
        # Check if the expression is safe
        if not is_safe(tree, allowed_ops, allowed_modules):
            raise ValueError("Invalid or unsafe expression")
        # Evaluate the expression
        result = eval(expr, {'__builtins__': None}, {'math': math})
        return result
    except Exception as e:
        return f"Error: {str(e)}"

def is_safe(node, allowed_ops, allowed_modules):
    if isinstance(node, ast.Expression):
        return is_safe(node.body, allowed_ops, allowed_modules)
    if isinstance(node, ast.BinOp):
        left = node.left
        right = node.right
        if isinstance(left, ast.Name) and left.id in allowed_ops:
            return is_safe(right, allowed_ops, allowed_modules)
        if isinstance(right, ast.Name) and right.id in allowed_ops:
            return is_safe(left, allowed_ops, allowed_modules)
        return is_safe(left, allowed_ops, allowed_modules) and is_safe(right, allowed_ops, allowed_modules)
    if isinstance(node, ast.UnaryOp):
        operand = node.operand
        if isinstance(operand, ast.Name) and operand.id in allowed_ops:
            return is_safe(operand, allowed_ops, allowed_modules)
        return is_safe(operand, allowed_ops, allowed_modules)
    if isinstance(node, ast.Call):
        func = node.func
        if isinstance(func, ast.Name) and func.id in allowed_modules:
            args = node.args
            for arg in args:
                if not isinstance(arg, ast.Name) and not isinstance(arg, ast.Num):
                    return False
            return True
        return False
    if isinstance(node, ast.Name):
        return node.id in allowed_ops
    if isinstance(node, ast.Num):
        return True
    return False

