def search_files(directory, pattern, recursive=False):
    """Search for files matching the pattern in the given directory."""
    matches = []
    for root, dirs, files in os.walk(directory) if recursive else os.walk(directory):
        for file in files:
            if fnmatch.fnmatch(file, pattern):
                matches.append(os.path.join(root, file))
    return matches

