            expire_file = os.path.join(self.cache_dir, f"{key}_expire.pkl")
            with open(expire_file, 'wb') as f:
                pickle.dump(expire_time, f)

    def delete(self, key):
        """Delete an object from the cache."""
        file_path = os.path.join(self.cache_dir, f"{key}.pkl")
        expire_file = os.path.join(self.cache_dir, f"{key}_expire.pkl")
        for f in [file_path, expire_file]:
